import re
lines=open("docs/progress.md").read().splitlines()
heads=[]
for i,l in enumerate(lines):
    m=re.match(r'^## Week (\d) —',l)
    if m: heads.append((int(m.group(1)),i))
    if l.startswith('## Aggregate'): heads.append(('END',i))
ranges={}
for idx in range(len(heads)-1):
    num,start=heads[idx]; end=heads[idx+1][1]
    if num!='END': ranges[num]=(start,end)

def flags(l):
    f=[]
    if 'moved to Week' in l: f.append('MOVED-OUT')
    if 'moved from Week' in l: f.append('MOVED-IN')
    if 'out-of-roadmap' in l.lower(): f.append('OOR-TAG')
    return f

for wk in sorted(ranges):
    start,end=ranges[wk]
    in_oo=False
    cls_lines=[]
    for i in range(start,end):
        l=lines[i]
        if l.startswith('### Out-of-roadmap'): in_oo=True
        elif l.startswith('### '): in_oo=False
        m=re.match(r'^- \[([ x~-])\]',l)
        if not m: continue
        status='✅' if '✅' in l else ('🟡' if '🟡' in l else ('🔵' if '🔵' in l else '⬜'))
        fl=flags(l)
        if in_oo: fl.append('OOR-SECTION')
        cls_lines.append((status,fl,l[:80]))
    # tally excluding OOR + MOVED-OUT
    d=ip=pe=excl=0
    for status,fl,_ in cls_lines:
        if 'OOR-SECTION' in fl or 'OOR-TAG' in fl or 'MOVED-OUT' in fl:
            excl+=1; continue
        if status=='✅': d+=1
        elif status=='🟡': ip+=1
        else: pe+=1
    print(f"\n===== Week {wk}: counted total={d+ip+pe} (done{d}/inprog{ip}/pend{pe}); excluded={excl} =====")
    for status,fl,txt in cls_lines:
        tag=(' <<'+','.join(fl)+'>>') if fl else ''
        print(f"  {status} {txt}{tag}")
